		// item盒子
		.list_item {
			// label
			.list_label {
			}
			// 输入框
			.list_inp {
			}
		}
		// 验证码
		.listCode_view {
			// label
			.listCode_label {
			}
			// 验证码输入框
			.listCode_inp {
			}
			// 验证码按钮
			.listCode_btn {
			}
		}
		// 用户类型样式
		.list_type {
			// 未选中样式
			:deep(.el-radio) {
				// 单选框
				.el-radio__inner {
				}
				// 提示文字
				.el-radio__label{
				}
			}
			// 选中样式
			:deep(.is-checked) {
				// 单选框
				.el-radio__inner {
				}
				// 提示文字
				.el-radio__label{
				}
			}
		}
		// 按钮盒子
		.btn_view {
			// 登录
			.login {
